long long solve(vector<long long> value, vector<long long> limit) {
    int n = value.size();
    vector<pair<long long, int>> elements;

    // Create a list of elements with their values and indices
    for (int i = 0; i < n; ++i) {
        elements.push_back({value[i], i});
    }

    // Sort elements by value in descending order
    sort(elements.begin(), elements.end(), greater<pair<long long, int>>());

    priority_queue<int, vector<int>, greater<int>> pq; // Min-heap to track active elements
    long long total = 0;

    for (int i = 0; i < n; ++i) {
        // Check if current element can be activated
        int current_limit = limit[elements[i].second];
        int active_count = pq.size();

        if (active_count < current_limit) {
            // Activate the element
            total += elements[i].first;
            pq.push(elements[i].second);
        }

        // After activation, check which elements become inactive
        while (!pq.empty() && limit[pq.top()] <= active_count + 1) {
            int inactive_idx = pq.top();
            pq.pop();
            // Mark the element as inactive (we don't need to track it anymore)
        }
    }

    return total;
}

